import { FieldPacket, QueryResult } from 'mysql2/typings/mysql/lib/protocol/packets';
import { QueryOptions, QueryValues, QueryableConstructor } from 'mysql2/typings/mysql/lib/protocol/sequences/Query.js';

export declare function QueryableBase<T extends QueryableConstructor>(
  Base?: T
): {
  new (...args: any[]): {
    query<T extends QueryResult>(
      sql: string,
      values?: QueryValues
    ): Promise<[T, FieldPacket[]]>;

    query<T extends QueryResult>(
      options: QueryOptions,
      values?: QueryValues
    ): Promise<[T, FieldPacket[]]>;
  };
} & T;
